"use client";

import { Progress as ProgressPrimitive } from "@base-ui/react/progress";

import * as stylex from "@stylexjs/stylex";

import { styles } from "./progress.stylex";

const Progress = ({
  className,
  style,
  children,
  ...props
}: Omit<React.ComponentProps<typeof ProgressPrimitive.Root>, "className"> & {
  className?: string;
}) => {
  const wrapper = stylex.props(styles.rootWrapper);
  return (
    <ProgressPrimitive.Root
      className={[wrapper.className, className].filter(Boolean).join(" ") || undefined}
      data-slot="progress"
      style={{ ...wrapper.style, ...style }}
      {...props}
    >
      {children}
      <ProgressPrimitive.Track
        className={stylex.props(styles.root).className}
        data-slot="progress-track"
      >
        <ProgressPrimitive.Indicator
          className={stylex.props(styles.indicator).className}
          data-slot="progress-indicator"
        />
      </ProgressPrimitive.Track>
    </ProgressPrimitive.Root>
  );
};

const ProgressLabel = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof ProgressPrimitive.Label>, "className"> & {
  className?: string;
}) => {
  const p = stylex.props(styles.label);
  return (
    <ProgressPrimitive.Label
      className={[p.className, className].filter(Boolean).join(" ") || undefined}
      data-slot="progress-label"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ProgressValue = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof ProgressPrimitive.Value>, "className"> & {
  className?: string;
}) => {
  const p = stylex.props(styles.value);
  return (
    <ProgressPrimitive.Value
      className={[p.className, className].filter(Boolean).join(" ") || undefined}
      data-slot="progress-value"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

export { Progress, ProgressLabel, ProgressValue };

import * as stylex from "@stylexjs/stylex";

import { colors } from "../tokens.stylex";

export const styles = stylex.create({
  indicator: {
    backgroundColor: colors.primary,
    height: "100%",
    transition: "all 0.2s ease-in-out",
    width: "100%",
  },
  label: {
    fontSize: "0.875rem",
    fontWeight: 500,
  },
  root: {
    backgroundColor: `color-mix(in oklab, ${colors.primary} 20%, transparent)`,
    borderRadius: "9999px",
    height: "0.5rem",
    overflow: "hidden",
    position: "relative",
    width: "100%",
  },
  rootWrapper: {
    display: "flex",
    flexDirection: "column",
    gap: "0.5rem",
    width: "100%",
  },
  track: {
    height: "100%",
    width: "100%",
  },
  value: {
    color: colors.mutedForeground,
    fontSize: "0.875rem",
  },
});
